// ─── Linked List in JavaScript ──────────────────────────────────────────────

class Node {
  constructor(value) {
    this.value = value;
    this.next = null;
  }
}

class LinkedList {
  constructor() {
    this.head = null;
    this.tail = null;
    this.size = 0;
  }

  // O(1) — Prepend (insert at head)
  prepend(value) {
    const node = new Node(value);
    if (!this.head) { this.head = this.tail = node; }
    else { node.next = this.head; this.head = node; }
    this.size++;
  }

  // O(1) with tail ptr — Append (insert at tail)
  append(value) {
    const node = new Node(value);
    if (!this.tail) { this.head = this.tail = node; }
    else { this.tail.next = node; this.tail = node; }
    this.size++;
  }

  // O(n) — Insert at index
  insertAt(index, value) {
    if (index < 0 || index > this.size) throw new RangeError('Index out of bounds');
    if (index === 0) return this.prepend(value);
    if (index === this.size) return this.append(value);
    const node = new Node(value);
    let curr = this.head;
    for (let i = 0; i < index - 1; i++) curr = curr.next;
    node.next = curr.next;
    curr.next = node;
    this.size++;
  }

  // O(1) — Delete head
  deleteHead() {
    if (!this.head) return null;
    const val = this.head.value;
    this.head = this.head.next;
    if (!this.head) this.tail = null;
    this.size--;
    return val;
  }

  // O(n) — Delete tail
  deleteTail() {
    if (!this.head) return null;
    if (this.head === this.tail) {
      const val = this.head.value;
      this.head = this.tail = null;
      this.size--;
      return val;
    }
    let curr = this.head;
    while (curr.next !== this.tail) curr = curr.next;
    const val = this.tail.value;
    curr.next = null;
    this.tail = curr;
    this.size--;
    return val;
  }

  // O(n) — Search
  search(value) {
    let curr = this.head, index = 0;
    while (curr) {
      if (curr.value === value) return index;
      curr = curr.next; index++;
    }
    return -1;
  }

  // O(n) — Get by index
  get(index) {
    if (index < 0 || index >= this.size) throw new RangeError('Index out of bounds');
    let curr = this.head;
    for (let i = 0; i < index; i++) curr = curr.next;
    return curr.value;
  }

  // O(n) — Reverse in-place
  reverse() {
    let prev = null, curr = this.head;
    this.tail = this.head;
    while (curr) {
      const next = curr.next;
      curr.next = prev;
      prev = curr; curr = next;
    }
    this.head = prev;
  }

  // O(n), O(1) — Detect cycle (Floyd's tortoise and hare)
  hasCycle() {
    let slow = this.head, fast = this.head;
    while (fast && fast.next) {
      slow = slow.next;
      fast = fast.next.next;
      if (slow === fast) return true;
    }
    return false;
  }
}

// ── Doubly Linked List Node ──────────────────────────────────────────────
class DNode {
  constructor(value) {
    this.value = value;
    this.next = null;
    this.prev = null;   // extra pointer — O(1) delete without predecessor
  }
}

// ── Circular Linked List — tail.next points back to head ─────────────────
class CircularLinkedList {
  constructor() { this.head = null; this.size = 0; }

  append(value) {
    const node = new Node(value);
    if (!this.head) { node.next = node; this.head = node; }
    else {
      let tail = this.head;
      while (tail.next !== this.head) tail = tail.next;
      tail.next = node;
      node.next = this.head;
    }
    this.size++;
  }
}

# ─── Linked List in Python ──────────────────────────────────────────────────

class Node:
    __slots__ = ('value', 'next')
    def __init__(self, value):
        self.value = value
        self.next  = None

class LinkedList:
    def __init__(self):
        self.head = None
        self.tail = None
        self.size = 0

    def prepend(self, value):
        node = Node(value)
        if not self.head: self.head = self.tail = node
        else: node.next = self.head; self.head = node
        self.size += 1

    def append(self, value):
        node = Node(value)
        if not self.tail: self.head = self.tail = node
        else: self.tail.next = node; self.tail = node
        self.size += 1

    def insert_at(self, index, value):
        if not (0 <= index <= self.size): raise IndexError('Out of bounds')
        if index == 0: return self.prepend(value)
        if index == self.size: return self.append(value)
        node = Node(value)
        curr = self.head
        for _ in range(index - 1): curr = curr.next
        node.next = curr.next; curr.next = node
        self.size += 1

    def delete_head(self):
        if not self.head: return None
        val = self.head.value
        self.head = self.head.next
        if not self.head: self.tail = None
        self.size -= 1
        return val

    def delete_tail(self):
        if not self.head: return None
        if self.head is self.tail:
            val = self.head.value; self.head = self.tail = None; self.size -= 1; return val
        curr = self.head
        while curr.next is not self.tail: curr = curr.next
        val = self.tail.value; curr.next = None; self.tail = curr
        self.size -= 1; return val

    def search(self, value):
        curr, idx = self.head, 0
        while curr:
            if curr.value == value: return idx
            curr, idx = curr.next, idx + 1
        return -1

    def get(self, index):
        if not (0 <= index < self.size): raise IndexError('Out of bounds')
        curr = self.head
        for _ in range(index): curr = curr.next
        return curr.value

    def reverse(self):
        prev, curr = None, self.head
        self.tail = self.head
        while curr:
            curr.next, prev, curr = prev, curr, curr.next
        self.head = prev

    def has_cycle(self):
        slow = fast = self.head
        while fast and fast.next:
            slow, fast = slow.next, fast.next.next
            if slow is fast: return True
        return False

