// ─── Linked List in Java ─────────────────────────────────────────────────────

public class LinkedList<T> {

    private static class Node<T> {
        T value; Node<T> next;
        Node(T v) { value = v; }
    }

    private Node<T> head, tail;
    private int size;

    public void prepend(T value) {
        Node<T> node = new Node<>(value);
        if (head == null) { head = tail = node; }
        else { node.next = head; head = node; }
        size++;
    }

    public void append(T value) {
        Node<T> node = new Node<>(value);
        if (tail == null) { head = tail = node; }
        else { tail.next = node; tail = node; }
        size++;
    }

    public void insertAt(int index, T value) {
        if (index < 0 || index > size) throw new IndexOutOfBoundsException();
        if (index == 0)    { prepend(value); return; }
        if (index == size) { append(value);  return; }
        Node<T> node = new Node<>(value), curr = head;
        for (int i = 0; i < index - 1; i++) curr = curr.next;
        node.next = curr.next; curr.next = node; size++;
    }

    public T deleteHead() {
        if (head == null) return null;
        T val = head.value; head = head.next;
        if (head == null) tail = null;
        size--; return val;
    }

    public T deleteTail() {
        if (head == null) return null;
        if (head == tail) { T v = head.value; head = tail = null; size--; return v; }
        Node<T> curr = head;
        while (curr.next != tail) curr = curr.next;
        T val = tail.value; curr.next = null; tail = curr; size--; return val;
    }

    public int search(T value) {
        Node<T> curr = head; int idx = 0;
        while (curr != null) {
            if (curr.value.equals(value)) return idx;
            curr = curr.next; idx++;
        }
        return -1;
    }

    public T get(int index) {
        if (index < 0 || index >= size) throw new IndexOutOfBoundsException();
        Node<T> curr = head;
        for (int i = 0; i < index; i++) curr = curr.next;
        return curr.value;
    }

    public void reverse() {
        Node<T> prev = null, curr = head; tail = head;
        while (curr != null) {
            Node<T> next = curr.next; curr.next = prev; prev = curr; curr = next;
        }
        head = prev;
    }

    public boolean hasCycle() {
        Node<T> slow = head, fast = head;
        while (fast != null && fast.next != null) {
            slow = slow.next; fast = fast.next.next;
            if (slow == fast) return true;
        }
        return false;
    }

    public int size() { return size; }
}

// ─── Linked List in C++ ──────────────────────────────────────────────────────

#include <stdexcept>

template<typename T>
class LinkedList {
    struct Node { T value; Node* next = nullptr; explicit Node(T v) : value(v) {} };
    Node* head = nullptr; Node* tail = nullptr; int sz = 0;

public:
    ~LinkedList() { Node* c = head; while (c) { Node* n = c->next; delete c; c = n; } }

    void prepend(T v) {
        Node* n = new Node(v);
        if (!head) head = tail = n; else { n->next = head; head = n; } sz++;
    }
    void append(T v) {
        Node* n = new Node(v);
        if (!tail) head = tail = n; else { tail->next = n; tail = n; } sz++;
    }
    T deleteHead() {
        if (!head) throw std::underflow_error("empty");
        T v = head->value; Node* old = head; head = head->next;
        if (!head) tail = nullptr; delete old; sz--; return v;
    }
    T deleteTail() {
        if (!head) throw std::underflow_error("empty");
        if (head == tail) { T v = head->value; delete head; head = tail = nullptr; sz--; return v; }
        Node* c = head; while (c->next != tail) c = c->next;
        T v = tail->value; delete tail; tail = c; tail->next = nullptr; sz--; return v;
    }
    int search(T v) const {
        Node* c = head; int i = 0;
        while (c) { if (c->value == v) return i; c = c->next; i++; } return -1;
    }
    T get(int i) const {
        if (i < 0 || i >= sz) throw std::out_of_range("out of bounds");
        Node* c = head; for (int j = 0; j < i; j++) c = c->next; return c->value;
    }
    void reverse() {
        Node* prev = nullptr; Node* c = head; tail = head;
        while (c) { Node* n = c->next; c->next = prev; prev = c; c = n; } head = prev;
    }
    bool hasCycle() const {
        Node* s = head; Node* f = head;
        while (f && f->next) { s = s->next; f = f->next->next; if (s == f) return true; }
        return false;
    }
    int size() const { return sz; }
};
